async function deleteResponse(id){let r=responses.find(x=>x.id===id);if(!r)return;let who=[r.memberName,r.employeeNo].filter(Boolean).join('／')||'這筆未具名回覆';if(!confirm(`確定要刪除「${who}」的填寫結果嗎？\n刪除後同仁可以重新填寫。`))return;if(!confirm(`再次確認：即將永久刪除「${who}」的資料，此動作無法復原。`))return;try{let batch=db.batch();batch.delete(doc('universalResponses',id));if(r.formId&&r.memberId)batch.delete(doc('universalResponseLocks',`${r.formId}__${r.memberId}`));await batch.commit();await loadResponses();renderAdmin();showPanel('resultsPanel');toast('填寫結果與填寫鎖定已刪除，同仁可重新填寫')}catch(e){console.error(e);alert('刪除失敗，請確認管理員權限與 v1.10 Firestore 規則')}}
function selectionQuestions(f){return(f.questions||[]).filter(q=>['single','dropdown','department','multiple'].includes(q.type))}
function questionOptionLabels(q){return optionCounts(q).map(x=>x.label)}
function responseHasOption(r,q,option){let value=r.answers?.[q.id];return Array.isArray(value)?value.map(String).includes(String(option)):String(value??'')===String(option)}
function cleanSummarySheet(f){let total=responses.length,questions=selectionQuestions(f),maxCols=Math.max(4,...questions.map(q=>questionOptionLabels(q).length+2)),rows=[['問卷選項統計總表'],['問卷名稱',f.title],['總填寫份數',total],['匯出時間',new Date().toLocaleString('zh-TW')],[]],merges=[{s:{r:0,c:0},e:{r:0,c:maxCols-1}}];if(!questions.length){rows.push(['目前沒有可統計的選項題目']);merges.push({s:{r:5,c:0},e:{r:5,c:maxCols-1}})}for(let q of questions){let items=optionCounts(q),isMultiple=q.type==='multiple',titleRow=rows.length;rows.push([`${q.title}${isMultiple?'（複選）':''}`]);merges.push({s:{r:titleRow,c:0},e:{r:titleRow,c:Math.max(1,items.length+1)}});rows.push(['選項',...items.map(x=>x.label),'合計']);let sum=items.reduce((n,x)=>n+x.count,0);rows.push(['數量',...items.map(x=>x.count),sum]);rows.push(['占填寫人數',...items.map(x=>percentage(x.count,total)+'%'),isMultiple?'—':percentage(sum,total)+'%']);rows.push([])}let sheet=XLSX.utils.aoa_to_sheet(rows);sheet['!merges']=merges;sheet['!cols']=[{wch:18},...Array.from({length:maxCols-1},()=>({wch:13}))];return sheet}
function departmentCrossSheet(f){let questions=selectionQuestions(f),configured=departments.map(d=>d.name||d.departmentName||d.department||'').filter(Boolean),used=[...new Set(responses.map(r=>r.departmentName||'未填部門'))],depNames=[...configured.filter(d=>used.includes(d)),...used.filter(d=>!configured.includes(d))],maxCols=Math.max(4,...questions.map(q=>questionOptionLabels(q).length+2)),rows=[['部門 × 選項交叉統計'],['問卷名稱',f.title],['總填寫份數',responses.length],[]],merges=[{s:{r:0,c:0},e:{r:0,c:maxCols-1}}];if(f.identityMode!=='member'){rows.push(['此問卷未使用公司人員資料，因此沒有部門交叉統計。']);merges.push({s:{r:4,c:0},e:{r:4,c:maxCols-1}})}else if(!questions.length){rows.push(['目前沒有可統計的選項題目。']);merges.push({s:{r:4,c:0},e:{r:4,c:maxCols-1}})}else for(let q of questions){let options=questionOptionLabels(q),titleRow=rows.length;rows.push([q.title]);merges.push({s:{r:titleRow,c:0},e:{r:titleRow,c:Math.max(1,options.length+1)}});rows.push(['部門',...options,'合計']);for(let dep of depNames){let depResponses=responses.filter(r=>(r.departmentName||'未填部門')===dep),counts=options.map(o=>depResponses.filter(r=>responseHasOption(r,q,o)).length);rows.push([dep,...counts,counts.reduce((n,x)=>n+x,0)])}let totals=options.map(o=>responses.filter(r=>responseHasOption(r,q,o)).length);rows.push(['總計',...totals,totals.reduce((n,x)=>n+x,0)]);rows.push([])}let sheet=XLSX.utils.aoa_to_sheet(rows);sheet['!merges']=merges;sheet['!cols']=[{wch:18},...Array.from({length:maxCols-1},()=>({wch:13}))];return sheet}
function exportResults(){let f=activeForm();if(!f)return alert('請先選擇問卷');let qs=(f.questions||[]).filter(q=>q.type!=='image'),detailRows=responses.map(r=>{let row={'送出時間':r.submittedAtText||''};if(f.identityMode==='member'){row['部門']=r.departmentName||'';row['姓名']=r.memberName||'';row['員工編號']=r.employeeNo||''}qs.forEach(q=>row[q.title]=answerText(q,r));return row}),detailSheet=detailRows.length?XLSX.utils.json_to_sheet(detailRows):XLSX.utils.aoa_to_sheet([['目前尚無填寫明細']]);detailSheet['!cols']=[{wch:21},...(f.identityMode==='member'?[{wch:14},{wch:14},{wch:12}]:[]),...qs.map(()=>({wch:24}))];let wb=XLSX.utils.book_new();XLSX.utils.book_append_sheet(wb,cleanSummarySheet(f),'選項統計總表');XLSX.utils.book_append_sheet(wb,departmentCrossSheet(f),'部門交叉統計');if(f.identityMode==='member'){XLSX.utils.book_append_sheet(wb,completionProgressSheet(f),'填寫進度');XLSX.utils.book_append_sheet(wb,missingMembersSheet(f),'未填寫名單')}XLSX.utils.book_append_sheet(wb,detailSheet,'填寫明細');XLSX.writeFile(wb,(f.title||'問卷')+'_統計報表.xlsx')}

/* v1.13：每份問卷獨立權限 */
async function loadCurrentAssignments(user){if(!user?.email)return[];try{let q=await col('universalFormManagers').where('email','==',normalizeEmail(user.email)).get();return q.docs.map(x=>({id:x.id,...x.data()}))}catch(e){console.warn('讀取問卷指派失敗，請發布 v1.13 Firestore 規則',e);return[]}}
function assignmentFor(formId){return formAssignments.find(x=>x.formId===formId&&x.enabled!==false)||null}
function canViewForm(formId){return isSystemAdmin||!!assignmentFor(formId)}
function canManageForm(formId){let a=assignmentFor(formId);return isSystemAdmin||!!(a&&a.role==='manager')}
function accessibleForms(includeDeleted=false){return forms.filter(f=>(includeDeleted||f.deleted!==true)&&canViewForm(f.id))}
function adminRouteId(){let m=location.hash.match(/^#admin\/([^/?#]+)/);return m?decodeURIComponent(m[1]):''}

async function loadPublicData(){let[fs,ds,ms]=await Promise.all([col('universalForms').get(),col('departments').get(),col('members').get()]);forms=fs.docs.map(x=>({id:x.id,...x.data()})).sort((a,b)=>(b.createdAt?.seconds||0)-(a.createdAt?.seconds||0));departments=ds.docs.map(x=>({id:x.id,...x.data()})).sort((a,b)=>(a.sortOrder??999)-(b.sortOrder??999));let depOrder=new Map(departments.map((d,i)=>[d.name||d.departmentName||d.department||'',i]));members=ms.docs.map(x=>({id:x.id,...x.data()})).sort((a,b)=>{let ad=a.department||a.departmentName||'',bd=b.department||b.departmentName||'',diff=(depOrder.get(ad)??9999)-(depOrder.get(bd)??9999);if(diff)return diff;return String(a.employeeNo||a.empNo||'').localeCompare(String(b.employeeNo||b.empNo||''),'zh-Hant',{numeric:true})||String(a.name||'').localeCompare(String(b.name||''),'zh-Hant')});let publicForms=forms.filter(f=>f.deleted!==true),route=formRouteId(),adminId=adminRouteId(),allowed=isAdmin?accessibleForms():[];if(adminId&&allowed.some(f=>f.id===adminId))activeFormId=adminId;else if(route&&publicForms.some(f=>f.id===route))activeFormId=route;else if(isAdmin&&allowed.length&&!allowed.some(f=>f.id===activeFormId))activeFormId=allowed[0].id;else if(!isAdmin&&!publicForms.some(f=>f.id===activeFormId))activeFormId=(publicForms.find(f=>f.state==='open')||publicForms[0])?.id||''}
async function loadAdminData(){await loadPublicData();await loadMemberAccounts();if(isSystemAdmin&&!submissionLocksPrepared)await prepareSubmissionLocks();await loadResponses();renderAdmin()}
async function loadResponses(){if(!isAdmin||!activeFormId||!canViewForm(activeFormId)){responses=[];return}try{let q=await col('universalResponses').where('formId','==',activeFormId).get();responses=q.docs.map(x=>({id:x.id,...x.data()})).sort((a,b)=>(b.submittedAt?.seconds||0)-(a.submittedAt?.seconds||0))}catch(e){console.warn(e);responses=[]}}
function applyRoute(){let wantsAdmin=location.hash==='#admin'||location.hash.startsWith('#admin/');if(wantsAdmin&&isAdmin){front.style.display='none';admin.style.display='block';loginMask.style.display='none';let routeId=adminRouteId();if(routeId&&canViewForm(routeId)&&routeId!==activeFormId){activeFormId=routeId;loadResponses().then(renderAdmin);return}renderAdmin();return}admin.style.display='none';front.style.display='block';loginMask.style.display=wantsAdmin&&!isAdmin?'grid':'none';renderFront();if(loginPurpose==='response'&&currentUser)setTimeout(showMyResponse,0)}
function myResponseButton(f){return f?.identityMode==='member'?'<button class="ghostBtn" type="button" onclick="startMyResponseView()">查看我的填寫結果</button>':''}
function renderFront(){let publicForms=forms.filter(x=>x.deleted!==true),f=publicForms.find(x=>x.id===(formRouteId()||activeFormId))||publicForms.find(x=>x.state==='open')||publicForms[0];if(!f){formStatus.textContent='尚無問卷';frontMain.innerHTML='<div class="successCard"><h2>目前尚無可填寫問卷</h2><p>請洽管理者建立問卷。</p></div>';return}activeFormId=f.id;let closed=f.state!=='open'||deadlinePassed(f.deadline);formStatus.textContent=closed?'問卷已關閉':'問卷開放中';let actions=document.querySelector('.frontActions');if(actions)actions.innerHTML=`<span id="formStatus" class="statusPill">${closed?'問卷已關閉':'問卷開放中'}</span>${myResponseButton(f)}<button class="ghostBtn" onclick="openAdmin()">管理登入</button>`;let heroImage=imageUrl(f.imageUrl);frontMain.innerHTML=`<section class="formHero"><h1>${esc(f.title)}</h1><p>${esc(f.description||'')}</p>${f.deadline?`<span class="deadlineBadge">請於 ${esc(formatDeadline(f.deadline))} 前完成</span>`:''}${heroImage?`<img class="referenceImage" src="${attr(heroImage)}" alt="問卷參考圖片">`:''}</section><div id="myResponseBox"></div>${closed?'<div class="successCard" style="margin-top:18px"><h2>本問卷目前未開放填寫</h2></div>':`<form id="publicForm" class="questionList" onsubmit="submitResponse(event)">${f.identityMode==='member'?renderIdentityBlock(f):''}${(f.questions||[]).map(renderPublicQuestion).join('')}<div class="submitArea"><button id="submitBtn" class="btn primary" type="submit">確認並送出</button><span id="submitNote" class="questionHelp"></span></div></form>`}`}

async function startMyResponseView(){loginPurpose='response';loginMsg.textContent='';if(!currentUser){loginMask.style.display='grid';return}await loadMemberAccounts();await showMyResponse()}
async function showMyResponse(){let box=$('myResponseBox'),f=activeForm();if(!box||!f)return;let member=findMemberByGoogleEmail(currentUser?.email||'');if(!member){box.innerHTML='<div class="notice myResponseCard">找不到此 Google 帳號對應的人員資料，請確認是否使用公司行事曆同一組帳號。</div>';return}box.innerHTML='<div class="notice myResponseCard">正在讀取您的填寫內容…</div>';try{let snap=await doc('universalResponses',`${f.id}__${member.id}`).get();if(!snap.exists){box.innerHTML='<div class="notice myResponseCard">目前查無您的填寫紀錄。</div>';return}let r={id:snap.id,...snap.data()},questions=(f.questions||[]).filter(q=>q.type!=='image'),answers=questions.map(q=>`<div class="myAnswerItem"><b>${esc(q.title||'未命名題目')}</b><p>${esc(answerText(q,r)||'未填')}</p></div>`).join('');box.innerHTML=`<section class="notice myResponseCard"><h2>我的填寫結果</h2><p class="myResponseMeta"><span>${esc(r.departmentName||member.department||'')}</span><span>${esc(r.memberName||member.name||'')}</span><span>${esc(r.employeeNo||member.employeeNo||member.empNo||'')}</span><span>${esc(r.submittedAtText||'')}</span></p><div class="myAnswerList">${answers||'<div class="myAnswerItem"><p>此問卷沒有可顯示的題目。</p></div>'}</div></section>`}catch(e){console.error(e);box.innerHTML='<div class="notice myResponseCard">讀取失敗，請確認 Firestore 規則已部署 v1.19 完整合併版。</div>'}}

function renderShareMemberOptions(){let select=$('managerEmail');if(!select)return;let current=select.value,options=members.filter(m=>m.active!==false&&memberGoogleEmail(m)).map(m=>({email:memberGoogleEmail(m),label:memberDisplayName(m)||m.name||m.id}));select.innerHTML='<option value="">請選擇成員</option>'+options.map(x=>`<option value="${attr(x.email)}">${esc(x.label)}</option>`).join('');select.value=options.some(x=>x.email===current)?current:''}
function managerPersonLabel(email){let member=findMemberByGoogleEmail(email),label=memberDisplayName(member);return label?`<b>${esc(label)}</b>`:`<b class="muted">未對應人員</b>`}
function ensureAdminExtensions(){if(!$('permissionsPanel')){let resultNav=[...document.querySelectorAll('.sidebar .nav')].find(x=>x.textContent.includes('填寫結果'));resultNav?.insertAdjacentHTML('beforebegin','<button id="permissionsNav" class="nav" onclick="showPanel(\'permissionsPanel\',this);loadFormManagers()">權限管理</button>');$('resultsPanel')?.insertAdjacentHTML('beforebegin',`<section id="permissionsPanel" class="panel"><div class="card"><div class="sectionHead"><div><h2>問卷權限管理</h2><p>每份問卷獨立指派；管理者可編輯問卷及回覆，檢視者只能查看與匯出。</p></div></div><div class="permissionForm"><label>分享成員<select id="managerEmail"><option value="">請選擇成員</option></select><small class="questionHelp">Google 帳號係同仁部門行事曆使用之帳號；如帳號異動，請洽系統管理員修正後方可登入。</small></label><label>角色<select id="managerRole"><option value="manager">問卷管理者</option><option value="viewer">檢視者</option></select></label><button class="btn primary" onclick="saveFormManager()">新增／更新指派</button></div><div id="formManagersTable"></div></div></section>`)}if(!$('trashCard'))$('formsTable')?.parentElement?.insertAdjacentHTML('afterend','<div id="trashCard" class="card trashCard"><div class="sectionHead"><div><h2>已刪除問卷</h2><p>可復原，或由系統管理員永久刪除。</p></div></div><div id="trashTable"></div></div>');renderShareMemberOptions()}
function updateRoleUi(){ensureAdminExtensions();let navs=[...document.querySelectorAll('.sidebar .nav')];navs.forEach(n=>{let t=n.textContent.trim();if(t==='新增問卷'||t==='人員管理')n.style.display=isSystemAdmin?'':'none'});$('permissionsNav').style.display=isSystemAdmin?'':'none';$('trashCard').style.display=isSystemAdmin?'':'none';[...document.querySelectorAll('#formsPanel button')].filter(b=>/新增空白問卷|外套尺寸範本/.test(b.textContent)).forEach(b=>b.style.display=isSystemAdmin?'':'none');if(!isSystemAdmin&&$('membersPanel')?.classList.contains('active'))showPanel('formsPanel');if(activeFormId&&!canManageForm(activeFormId)&&$('editorPanel')?.classList.contains('active'))showPanel('resultsPanel')}
function renderAdmin(){ensureAdminExtensions();let list=accessibleForms();if(list.length&&!list.some(f=>f.id===activeFormId))activeFormId=list[0].id;activeFormSelect.innerHTML='<option value="">請選擇問卷</option>'+list.map(f=>`<option value="${attr(f.id)}" ${f.id===activeFormId?'selected':''}>${esc(f.title)}</option>`).join('');let f=activeForm();activeFormLabel.textContent=f?'目前問卷：'+f.title:'尚未選擇問卷';$('formCount').textContent=list.length;$('currentFormName').textContent=f?.title||'—';$('responseCount').textContent=responses.length;renderFormsTable();if(isSystemAdmin){renderMemberPanel();renderTrash();if($('permissionsPanel').classList.contains('active'))loadFormManagers()}renderResults();updateRoleUi()}
function renderFormsTable(){let list=accessibleForms();formsTable.innerHTML=table(['問卷','我的權限','狀態','截止時間','題數','操作'],list.map(f=>{let manage=canManageForm(f.id),role=isSystemAdmin?'系統管理員':manage?'問卷管理者':'檢視者';return `<tr><td><b>${esc(f.title)}</b><br><small>${esc(f.id)}</small></td><td><span class="roleBadge ${manage?'manager':'viewer'}">${role}</span></td><td><span class="statePill state-${attr(f.state||'draft')}">${esc(stateLabel(f.state))}</span></td><td>${esc(formatDeadline(f.deadline)||'未設定')}</td><td><span class="countPill">${(f.questions||[]).length}</span></td><td><div class="buttonRow tableActions">${manage?`<button class="btn" onclick="editForm('${attr(f.id)}')">編輯</button>`:''}<button class="btn" onclick="selectForm('${attr(f.id)}')">結果</button><button class="btn" onclick="copyFormLink('${attr(f.id)}')">前台</button><button class="btn" onclick="copyAdminLink('${attr(f.id)}')">後台</button>${manage?`<button class="btn danger" onclick="deleteForm('${attr(f.id)}')">刪除</button>`:''}</div></td></tr>`}))}
async function selectForm(id){if(!id||!canViewForm(id))return;activeFormId=id;history.replaceState(null,'','#admin/'+encodeURIComponent(id));await loadResponses();renderAdmin();showPanel('resultsPanel')}
function copyAdminLink(id=activeFormId){if(!id)return alert('請先選擇問卷');let url=location.href.split('#')[0]+'#admin/'+encodeURIComponent(id);navigator.clipboard?.writeText(url).then(()=>toast('專屬後台網址已複製')).catch(()=>prompt('請複製專屬後台網址',url))}

async function deleteForm(id){if(!canManageForm(id))return alert('您沒有刪除此問卷的權限');let f=forms.find(x=>x.id===id);if(!f)return;let snap=await col('universalResponses').where('formId','==',id).get(),count=snap.size;if(!confirm(`即將把問卷移至垃圾桶：\n${f.title}\n目前共有 ${count} 份回覆。\n\n移至垃圾桶後前台不再顯示，但資料仍可復原。`))return;let typed=prompt(`為避免誤刪，請完整輸入問卷名稱：\n${f.title}`);if(typed!==f.title)return alert('輸入的問卷名稱不一致，已取消刪除。');await doc('universalForms',id).set({deleted:true,deletedAt:firebase.firestore.FieldValue.serverTimestamp(),deletedBy:currentUser?.email||''},{merge:true});if(activeFormId===id)activeFormId='';await loadAdminData();showPanel('formsPanel');toast('問卷已移至垃圾桶')}
function renderTrash(){let deleted=forms.filter(f=>f.deleted===true);$('trashTable').innerHTML=table(['問卷','刪除者','操作'],deleted.map(f=>`<tr><td><b>${esc(f.title)}</b><br><small>${esc(f.id)}</small></td><td>${esc(f.deletedBy||'—')}</td><td><div class="buttonRow"><button class="btn" onclick="restoreForm('${attr(f.id)}')">復原</button><button class="btn danger" onclick="permanentlyDeleteForm('${attr(f.id)}')">永久刪除</button></div></td></tr>`))}
async function restoreForm(id){if(!isSystemAdmin)return;await doc('universalForms',id).update({deleted:false,deletedAt:firebase.firestore.FieldValue.delete(),deletedBy:firebase.firestore.FieldValue.delete()});await loadAdminData();toast('問卷已復原')}
async function deleteSnapshotInChunks(snapshot){let docs=snapshot.docs;for(let i=0;i<docs.length;i+=400){let batch=db.batch();docs.slice(i,i+400).forEach(x=>batch.delete(x.ref));await batch.commit()}}
async function permanentlyDeleteForm(id){if(!isSystemAdmin)return;let f=forms.find(x=>x.id===id);if(!f)return;let responseSnap=await col('universalResponses').where('formId','==',id).get();if(!confirm(`永久刪除後無法復原。\n問卷：${f.title}\n回覆：${responseSnap.size} 份\n\n確定繼續？`))return;if(prompt(`最後確認：請完整輸入問卷名稱\n${f.title}`)!==f.title)return alert('名稱不一致，已取消永久刪除。');let[lockSnap,managerSnap]=await Promise.all([col('universalResponseLocks').where('formId','==',id).get(),col('universalFormManagers').where('formId','==',id).get()]);await deleteSnapshotInChunks(responseSnap);await deleteSnapshotInChunks(lockSnap);await deleteSnapshotInChunks(managerSnap);await doc('universalForms',id).delete();await loadAdminData();toast('問卷及其回覆已永久刪除')}

async function loadFormManagers(){if(!isSystemAdmin||!activeFormId)return;$('formManagersTable').innerHTML='<p class="questionHelp">讀取中…</p>';try{let q=await col('universalFormManagers').where('formId','==',activeFormId).get();formManagers=q.docs.map(x=>({id:x.id,...x.data()})).sort((a,b)=>String(a.email).localeCompare(String(b.email)));renderFormManagers()}catch(e){console.error(e);$('formManagersTable').innerHTML='<p class="errorText">無法讀取權限資料，請確認已發布 v1.13 Firestore 規則。</p>'}}
function renderFormManagers(){$('formManagersTable').innerHTML=table(['分享成員','角色','狀態','操作'],formManagers.map(m=>`<tr><td>${managerPersonLabel(m.email)}</td><td><span class="roleBadge ${m.role==='manager'?'manager':'viewer'}">${m.role==='manager'?'問卷管理者':'檢視者'}</span></td><td><span class="statePill ${m.enabled===false?'state-closed':'state-open'}">${m.enabled===false?'停用':'啟用'}</span></td><td><div class="buttonRow tableActions"><button class="btn" onclick="toggleFormManager('${attr(m.id)}',${m.enabled===false?'true':'false'})">${m.enabled===false?'啟用':'停用'}</button><button class="btn danger" onclick="removeFormManager('${attr(m.id)}')">移除</button></div></td></tr>`))}
function managerDocumentId(formId,email){return formId+'__'+String(email).trim().toLowerCase()}
async function saveFormManager(){if(!isSystemAdmin||!activeFormId)return;let email=normalizeEmail($('managerEmail').value),role=$('managerRole').value;if(!/^\S+@\S+\.\S+$/.test(email))return alert('請選擇分享成員');let member=findMemberByGoogleEmail(email);if(!member)return alert('請從分享成員清單選擇人員');let id=managerDocumentId(activeFormId,email),existing=formManagers.find(x=>x.id===id),data={formId:activeFormId,email,role,enabled:true,memberId:member.id||'',displayName:memberDisplayName(member),updatedAt:firebase.firestore.FieldValue.serverTimestamp()};if(!existing)data.createdAt=firebase.firestore.FieldValue.serverTimestamp();await doc('universalFormManagers',id).set(data,{merge:true});$('managerEmail').value='';await loadFormManagers();toast(existing?'權限已更新':'已新增問卷權限')}
async function toggleFormManager(id,enabled){if(!isSystemAdmin)return;await doc('universalFormManagers',id).set({enabled,updatedAt:firebase.firestore.FieldValue.serverTimestamp()},{merge:true});await loadFormManagers();toast(enabled?'權限已啟用':'權限已停用')}
async function removeFormManager(id){if(!isSystemAdmin)return;let m=formManagers.find(x=>x.id===id);if(!confirm(`確定移除 ${m?.email||'此帳號'} 的問卷權限？`))return;await doc('universalFormManagers',id).delete();await loadFormManagers();toast('問卷權限已移除')}

function renderResults(){let f=activeForm(),progress=f?.identityMode==='member'?completionData(f):null;$('resultCaption').textContent=f?`${f.title}：共 ${responses.length} 份回覆${progress?`；應填 ${progress.expected.length} 人，未填 ${progress.missing.length} 人`:''}`:'請先選擇問卷。';if(!f){$('resultAnalysis').innerHTML='';resultsTable.innerHTML='';let p=$('missingResponsesPanel');if(p)p.style.display='none';return}$('resultAnalysis').innerHTML=renderAnalysis(f);renderMissingMembers(f);let qs=(f.questions||[]).filter(q=>q.type!=='image'),identityHeaders=f.identityMode==='member'?['部門','姓名','員工編號']:[],manage=canManageForm(f.id);resultsTable.innerHTML=table(['送出時間',...identityHeaders,...qs.map(q=>q.title),'操作'],responses.map(r=>`<tr><td>${esc(r.submittedAtText||'')}</td>${f.identityMode==='member'?`<td>${esc(r.departmentName||'')}</td><td>${esc(r.memberName||'')}</td><td>${esc(r.employeeNo||'')}</td>`:''}${qs.map(q=>`<td>${esc(answerText(q,r))}</td>`).join('')}<td>${manage?`<div class="buttonRow"><button class="btn" onclick="openResponseEditor('${attr(r.id)}')">編輯</button><button class="btn danger" onclick="deleteResponse('${attr(r.id)}')">刪除</button></div>`:'<span class="roleBadge viewer">唯讀</span>'}</td></tr>`))}

init().catch(e=>{console.error(e);frontMain.innerHTML='<div class="successCard"><h2>系統載入失敗</h2><p>'+esc(e.message||e)+'</p></div>'});
